    35→/**
    36→ * A pool of ByteBuffers kept under a given memory limit. This class is fairly specific to the needs of the producer. In
    37→ * particular it has the following properties:
    38→ * <ol>
    39→ * <li>There is a special "poolable size" and buffers of this size are kept in a free list and recycled
    40→ * <li>It is fair. That is all memory is given to the longest waiting thread until it has sufficient memory. This
    41→ * prevents starvation or deadlock when a thread asks for a large chunk of memory and needs to block until multiple
    42→ * buffers are deallocated.
    43→ * </ol>
    44→ */
    45→public class BufferPool {
    46→
    47→    static final String WAIT_TIME_SENSOR_NAME = "bufferpool-wait-time";
    48→
    49→    private final long totalMemory;
    50→    private final int poolableSize;
    51→    private final ReentrantLock lock;
    52→    private final Deque<ByteBuffer> free;
    53→    private final Deque<Condition> waiters;
    54→    /** Total available memory is the sum of nonPooledAvailableMemory and the number of byte buffers in free * poolableSize.  */
    55→    private long nonPooledAvailableMemory;
    56→    private final Metrics metrics;
    57→    private final Time time;
    58→    private final Sensor waitTime;
    59→    private boolean closed;
    60→
    61→    /**
    62→     * Create a new buffer pool
    63→     *
    64→     * @param memory The maximum amount of memory that this buffer pool can allocate
    65→     * @param poolableSize The buffer size to cache in the free list rather than deallocating
    66→     * @param metrics instance of Metrics
    67→     * @param time time instance
    68→     * @param metricGrpName logical group name for metrics
    69→     */
    70→    public BufferPool(long memory, int poolableSize, Metrics metrics, Time time, String metricGrpName) {
    71→        this.poolableSize = poolableSize;
    72→        this.lock = new ReentrantLock();
    73→        this.free = new ArrayDeque<>();
    74→        this.waiters = new ArrayDeque<>();
    75→        this.totalMemory = memory;
    76→        this.nonPooledAvailableMemory = memory;
    77→        this.metrics = metrics;
    78→        this.time = time;
    79→        this.waitTime = this.metrics.sensor(WAIT_TIME_SENSOR_NAME);
    80→        MetricName rateMetricName = metrics.metricName("bufferpool-wait-ratio",
    81→                                                   metricGrpName,
    82→                                                   "The fraction of time an appender waits for space allocation.");
    83→        MetricName totalNsMetricName = metrics.metricName("bufferpool-wait-time-ns-total",
    84→                                                    metricGrpName,
    85→                                                    "The total time in nanoseconds an appender waits for space allocation.");
    86→
    87→        Sensor bufferExhaustedRecordSensor = metrics.sensor("buffer-exhausted-records");
    88→        MetricName bufferExhaustedRateMetricName = metrics.metricName("buffer-exhausted-rate", metricGrpName, "The average per-second number of record sends that are dropped due to buffer exhaustion");
    89→        MetricName bufferExhaustedTotalMetricName = metrics.metricName("buffer-exhausted-total", metricGrpName, "The total number of record sends that are dropped due to buffer exhaustion");
    90→        bufferExhaustedRecordSensor.add(new Meter(bufferExhaustedRateMetricName, bufferExhaustedTotalMetricName));
    91→
    92→        this.waitTime.add(new Meter(TimeUnit.NANOSECONDS, rateMetricName, totalNsMetricName));
    93→        this.closed = false;
    94→    }
    95→
    96→    /**
    97→     * Allocate a buffer of the given size. This method blocks if there is not enough memory and the buffer pool
    98→     * is configured with blocking mode.
    99→     *
   100→     * @param size The buffer size to allocate in bytes
   101→     * @param maxTimeToBlockMs The maximum time in milliseconds to block for buffer memory to be available
   102→     * @return The buffer
   103→     * @throws InterruptedException If the thread is interrupted while blocked
   104→     * @throws IllegalArgumentException if size is larger than the total memory controlled by the pool (and hence we would block
   105→     *         forever)
   106→     */
   107→    public ByteBuffer allocate(int size, long maxTimeToBlockMs) throws InterruptedException {
   108→        if (size > this.totalMemory)
   109→            throw new IllegalArgumentException("Attempt to allocate " + size
   110→                                               + " bytes, but there is a hard limit of "
   111→                                               + this.totalMemory
   112→                                               + " on memory allocations.");
   113→
   114→        ByteBuffer buffer = null;
   115→        this.lock.lock();
   116→
   117→        if (this.closed) {
   118→            this.lock.unlock();
   119→            throw new KafkaException("Producer closed while allocating memory");
   120→        }
   121→
   122→        try {
   123→            // check if we have a free buffer of the right size pooled
   124→            if (size == poolableSize && !this.free.isEmpty())
   125→                return this.free.pollFirst();
   126→
   127→            // now check if the request is immediately satisfiable with the
   128→            // memory on hand or if we need to block
   129→            int freeListSize = freeSize() * this.poolableSize;
   130→            if (this.nonPooledAvailableMemory + freeListSize >= size) {
   131→                // we have enough unallocated or pooled memory to immediately
   132→                // satisfy the request, but need to allocate the buffer
   133→                freeUp(size);
   134→                this.nonPooledAvailableMemory -= size;
   135→            } else {
   136→                // we are out of memory and will have to block
   137→                int accumulated = 0;
   138→                Condition moreMemory = this.lock.newCondition();
   139→                try {
   140→                    long remainingTimeToBlockNs = TimeUnit.MILLISECONDS.toNanos(maxTimeToBlockMs);
   141→                    this.waiters.addLast(moreMemory);
   142→                    // loop over and over until we have a buffer or have reserved
   143→                    // enough memory to allocate one
   144→                    while (accumulated < size) {
   145→                        long startWaitNs = time.nanoseconds();
   146→                        long timeNs;
   147→                        boolean waitingTimeElapsed;
   148→                        try {
   149→                            waitingTimeElapsed = !moreMemory.await(remainingTimeToBlockNs, TimeUnit.NANOSECONDS);
   150→                        } finally {
   151→                            long endWaitNs = time.nanoseconds();
   152→                            timeNs = Math.max(0L, endWaitNs - startWaitNs);
   153→                            recordWaitTime(timeNs);
   154→                        }
   155→
   156→                        if (this.closed)
   157→                            throw new KafkaException("Producer closed while allocating memory");
   158→
   159→                        if (waitingTimeElapsed) {
   160→                            this.metrics.sensor("buffer-exhausted-records").record();
   161→                            throw new BufferExhaustedException("Failed to allocate " + size + " bytes within the configured max blocking time "
   162→                                + maxTimeToBlockMs + " ms. Total memory: " + totalMemory() + " bytes. Available memory: " + availableMemory()
   163→                                + " bytes. Poolable size: " + poolableSize() + " bytes");
   164→                        }
   165→
   166→                        remainingTimeToBlockNs -= timeNs;
   167→
   168→                        // check if we can satisfy this request from the free list,
   169→                        // otherwise allocate memory
   170→                        if (accumulated == 0 && size == this.poolableSize && !this.free.isEmpty()) {
   171→                            // just grab a buffer from the free list
   172→                            buffer = this.free.pollFirst();
   173→                            accumulated = size;
   174→                        } else {
   175→                            // we'll need to allocate memory, but we may only get
   176→                            // part of what we need on this iteration
   177→                            freeUp(size - accumulated);
   178→                            int got = (int) Math.min(size - accumulated, this.nonPooledAvailableMemory);
   179→                            this.nonPooledAvailableMemory -= got;
   180→                            accumulated += got;
   181→                        }
   182→                    }
   183→                    // Don't reclaim memory on throwable since nothing was thrown
   184→                    accumulated = 0;
   185→                } finally {
   186→                    // When this loop was not able to successfully terminate don't loose available memory
   187→                    this.nonPooledAvailableMemory += accumulated;
   188→                    this.waiters.remove(moreMemory);
   189→                }
   190→            }
   191→        } finally {
   192→            // signal any additional waiters if there is more memory left
   193→            // over for them
   194→            try {
   195→                if (!(this.nonPooledAvailableMemory == 0 && this.free.isEmpty()) && !this.waiters.isEmpty())
   196→                    this.waiters.peekFirst().signal();
   197→            } finally {
   198→                // Another finally... otherwise find bugs complains
   199→                lock.unlock();
   200→            }
   201→        }
   202→
   203→        if (buffer == null)
   204→            return safeAllocateByteBuffer(size);
   205→        else
   206→            return buffer;
   207→    }
   208→
   209→    // Protected for testing
   210→    protected void recordWaitTime(long timeNs) {
   211→        this.waitTime.record(timeNs, time.milliseconds());
   212→    }
   213→
   214→    /**
   215→     * Allocate a buffer.  If buffer allocation fails (e.g. because of OOM) then return the size count back to
   216→     * available memory and signal the next waiter if it exists.
   217→     */
   218→    private ByteBuffer safeAllocateByteBuffer(int size) {
   219→        boolean error = true;
   220→        try {
   221→            ByteBuffer buffer = allocateByteBuffer(size);
   222→            error = false;
   223→            return buffer;
   224→        } finally {
   225→            if (error) {
   226→                this.lock.lock();
   227→                try {
   228→                    this.nonPooledAvailableMemory += size;
   229→                    if (!this.waiters.isEmpty())
   230→                        this.waiters.peekFirst().signal();
   231→                } finally {
   232→                    this.lock.unlock();
   233→                }
   234→            }
   235→        }
   236→    }
   237→
   238→    // Protected for testing.
   239→    protected ByteBuffer allocateByteBuffer(int size) {
   240→        return ByteBuffer.allocate(size);
   241→    }
   242→
   243→    /**
   244→     * Attempt to ensure we have at least the requested number of bytes of memory for allocation by deallocating pooled
   245→     * buffers (if needed)
   246→     */
   247→    private void freeUp(int size) {
   248→        while (!this.free.isEmpty() && this.nonPooledAvailableMemory < size)
   249→            this.nonPooledAvailableMemory += this.free.pollLast().capacity();
   250→    }
   251→
   252→    /**
   253→     * Return buffers to the pool. If they are of the poolable size add them to the free list, otherwise just mark the
   254→     * memory as free.
   255→     *
   256→     * @param buffer The buffer to return
   257→     * @param size The size of the buffer to mark as deallocated, note that this may be smaller than buffer.capacity
   258→     *             since the buffer may re-allocate itself during in-place compression
   259→     */
   260→    public void deallocate(ByteBuffer buffer, int size) {
   261→        lock.lock();
   262→        try {
   263→            if (size == this.poolableSize && size == buffer.capacity()) {
   264→                buffer.clear();
   265→                this.free.add(buffer);
   266→            } else {
   267→                this.nonPooledAvailableMemory += size;
   268→            }
   269→            Condition moreMem = this.waiters.peekFirst();
   270→            if (moreMem != null)
   271→                moreMem.signal();
   272→        } finally {
   273→            lock.unlock();
   274→        }
   275→    }
   276→
   277→    public void deallocate(ByteBuffer buffer) {
   278→        if (buffer != null)
   279→            deallocate(buffer, buffer.capacity());
   280→    }
   281→
   282→    /**
   283→     * the total free memory both unallocated and in the free list
   284→     */
   285→    public long availableMemory() {
   286→        lock.lock();
   287→        try {
   288→            return this.nonPooledAvailableMemory + freeSize() * (long) this.poolableSize;
   289→        } finally {
   290→            lock.unlock();
   291→        }
   292→    }
   293→
   294→    // Protected for testing.
   295→    protected int freeSize() {
   296→        return this.free.size();
   297→    }
   298→
   299→    /**
   300→     * Get the unallocated memory (not in the free list or in use)
   301→     */
   302→    public long unallocatedMemory() {
   303→        lock.lock();
   304→        try {
   305→            return this.nonPooledAvailableMemory;
   306→        } finally {
   307→            lock.unlock();
   308→        }
   309→    }
   310→
   311→    /**
   312→     * The number of threads blocked waiting on memory
   313→     */
   314→    public int queued() {
   315→        lock.lock();
   316→        try {
   317→            return this.waiters.size();
   318→        } finally {
   319→            lock.unlock();
   320→        }
   321→    }
   322→
   323→    /**
   324→     * The buffer size that will be retained in the free list after use
   325→     */
   326→    public int poolableSize() {
   327→        return this.poolableSize;
   328→    }
   329→
   330→    /**
   331→     * The total memory managed by this pool
   332→     */
   333→    public long totalMemory() {
   334→        return this.totalMemory;
   335→    }
   336→
   337→    // package-private method used only for testing
   338→    Deque<Condition> waiters() {
   339→        return this.waiters;
   340→    }
   341→
   342→    /**
   343→     * Closes the buffer pool. Memory will be prevented from being allocated, but may be deallocated. All allocations
   344→     * awaiting available memory will be notified to abort.
   345→     */
   346→    public void close() {
   347→        this.lock.lock();
   348→        this.closed = true;
   349→        try {
   350→            for (Condition waiter : this.waiters)
   351→                waiter.signal();
   352→        } finally {
   353→            this.lock.unlock();
   354→        }
   355→    }
   356→}
